 11→#[derive(Parser, Debug)]
 12→#[command(version, about = "vc-x1: jj workspace tooling")]
 13→pub struct Cli {
 14→    #[command(subcommand)]
 15→    command: Commands,
 16→}
 17→
 18→#[derive(Subcommand, Debug)]
 19→enum Commands {
 20→    /// Print the changeID for a revision
 21→    Chid(chid::ChidArgs),
 22→
 23→    /// Show full description of a commit
 24→    Desc(desc::DescArgs),
 25→
 26→    /// List commits in a jj repo
 27→    List(list::ListArgs),
 28→
 29→    /// Squash working copy into target commit (daemonizes by default)
 30→    Finalize(finalize::FinalizeArgs),
 31→}
 32→
 33→fn main() -> ExitCode {
 34→    let cli = Cli::parse();
 35→
 36→    match cli.command {
 37→        Commands::Chid(args) => {
 38→            if let Err(e) = chid::chid(&args) {
 39→                eprintln!("error: {e}");
 40→                return ExitCode::FAILURE;
 41→            }
 42→            ExitCode::SUCCESS
 43→        }
 44→        Commands::Desc(args) => {
 45→            if let Err(e) = desc::desc(&args) {
 46→                eprintln!("error: {e}");
 47→                return ExitCode::FAILURE;
 48→            }
 49→            ExitCode::SUCCESS
 50→        }
 51→        Commands::List(args) => {
 52→            if let Err(e) = list::list(&args) {
 53→                eprintln!("error: {e}");
 54→                return ExitCode::FAILURE;
 55→            }
 56→            ExitCode::SUCCESS
 57→        }
 58→        Commands::Finalize(args) => {
 59→            let opts = args.into_opts();
 60→            finalize::log_msg(&opts.log, "main: finalize entry");
 61→            match finalize::finalize(&opts) {
 62→                Ok(()) => {
 63→                    finalize::log_msg(&opts.log, "main: finalize exit ok");
 64→                    ExitCode::SUCCESS
 65→                }
 66→                Err(e) => {
 67→                    finalize::log_msg(&opts.log, &format!("main: finalize exit err={e}"));
 68→                    eprintln!("error: {e}");
 69→                    ExitCode::FAILURE
 70→                }
 71→            }
 72→        }
 73→    }
 74→}
