 77→/// Resolve effective revision, limit, and whether results need reversing
 78→/// from positional args combined with named flags.
 79→///
 80→/// Named flags (`-r`, `-l`) take precedence over positional args.
 81→pub struct ResolvedArgs {
 82→    /// The jj revset string to evaluate.
 83→    pub revset: String,
 84→    /// Maximum number of commits to return (None = unlimited).
 85→    pub limit: Option<usize>,
 86→    /// For `..x..`, the count per side.
 87→    pub both_count: Option<usize>,
 88→}
 89→
 90→/// Resolve positional `..` args with named flag overrides.
 91→///
 92→/// - `pos_rev`: first positional arg (may contain `..`)
 93→/// - `pos_count`: second positional arg
 94→/// - `flag_rev`: `-r` flag value (if different from default)
 95→/// - `flag_limit`: `-l` flag value
 96→/// - `default_rev`: the default revision (e.g. "@")
 97→pub fn resolve_dot_args(
 98→    pos_rev: Option<&str>,
 99→    pos_count: Option<usize>,
100→    flag_rev: &str,
101→    flag_limit: Option<usize>,
102→    default_rev: &str,
103→) -> ResolvedArgs {
104→    // If named flags were explicitly set, they take full precedence
105→    let flag_rev_set = flag_rev != default_rev;
106→    let flag_limit_set = flag_limit.is_some();
107→
108→    if flag_rev_set || (flag_limit_set && pos_rev.is_none()) {
109→        return ResolvedArgs {
110→            revset: flag_rev.to_string(),
111→            limit: flag_limit,
112→
113→            both_count: None,
114→        };
115→    }
116→
117→    // Use positional args
118→    let rev_str = pos_rev.unwrap_or(default_rev);
119→    let mut spec = parse_dot_rev(rev_str);
120→
121→    // If there's a positional count, set it
122→    if let Some(c) = pos_count {
123→        spec.count = c;
124→    }
125→
126→    // Named limit overrides positional count
127→    if flag_limit_set {
128→        spec.count = flag_limit.unwrap();
129→    }
130→
131→    match spec.direction {
132→        DotDirection::None => {
133→            if spec.count > 0 {
134→                // bare `x 5` → `x.. 5` (ancestors)
135→                ResolvedArgs {
136→                    revset: format!("::{}", spec.rev),
137→                    limit: Some(spec.count + 1), // +1 for x itself
138→
139→                    both_count: None,
140→                }
141→            } else {
142→                ResolvedArgs {
143→                    revset: spec.rev,
144→                    limit: Some(1),
145→
146→                    both_count: None,
147→                }
148→            }
149→        }
150→        DotDirection::Ancestors => {
151→            if spec.count > 0 {
152→                ResolvedArgs {
153→                    revset: format!("::{}", spec.rev),
154→                    limit: Some(spec.count + 1),
155→
156→                    both_count: None,
157→                }
158→            } else {
159→                ResolvedArgs {
160→                    revset: format!("::{}", spec.rev),
161→                    limit: None,
162→
163→                    both_count: None,
164→                }
165→            }
166→        }
167→        DotDirection::Descendants => {
168→            if spec.count > 0 {
169→                ResolvedArgs {
170→                    revset: format!("{}::", spec.rev),
171→                    limit: Some(spec.count + 1),
172→
173→                    both_count: None,
174→                }
175→            } else {
176→                ResolvedArgs {
177→                    revset: format!("{}::", spec.rev),
178→                    limit: None,
179→
180→                    both_count: None,
181→                }
182→            }
183→        }
184→        DotDirection::Both => ResolvedArgs {
185→            revset: format!("::{}|{}::", spec.rev, spec.rev),
186→            limit: None,
187→
188→            both_count: Some(spec.count),
189→        },
190→    }
191→}
