193→/// Format: just the short changeID.
194→pub fn format_chid(commit: &Commit) -> String {
195→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
196→    change_hex[..change_hex.len().min(12)].to_string()
197→}
198→
199→/// Format: changeID commitID first-line (single line).
200→pub fn format_commit_short(commit: &Commit) -> String {
201→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
202→    let change_short = &change_hex[..change_hex.len().min(12)];
203→    let commit_hex = commit.id().hex();
204→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
205→    let first_line = commit.description().lines().next().unwrap_or("");
206→    if first_line.is_empty() {
207→        format!("{change_short} {commit_short} (no description set)")
208→    } else {
209→        format!("{change_short} {commit_short} {first_line}")
210→    }
211→}
