213→/// Format: changeID commitID first-line, then remaining description lines.
214→pub fn format_commit_full(commit: &Commit) -> String {
215→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
216→    let change_short = &change_hex[..change_hex.len().min(12)];
217→    let commit_hex = commit.id().hex();
218→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
219→    let desc = commit.description();
220→    if desc.is_empty() {
221→        format!("{change_short} {commit_short} (no description set)")
222→    } else {
223→        let mut lines = desc.lines();
224→        let first_line = lines.next().unwrap_or("");
225→        let mut result = format!("{change_short} {commit_short} {first_line}");
226→        for line in lines {
227→            result.push('\n');
228→            result.push_str(line);
229→        }
230→        result
231→    }
232→}
