234→/// Collect formatted lines for `..x..` (both directions).
235→///
236→/// `formatter` converts a `Commit` into a display string.
237→/// Returns the lines in display order: descendants (newest first),
238→/// anchor, ancestors (newest first).
239→pub fn collect_both<F>(
240→    repo: &Arc<ReadonlyRepo>,
241→    repo_path: &Path,
242→    pos_rev: Option<&str>,
243→    both_count: usize,
244→    formatter: F,
245→) -> Result<Vec<String>, Box<dyn std::error::Error>>
246→where
247→    F: Fn(&Commit) -> String,
248→{
249→    let bare_rev = pos_rev.unwrap_or("@");
250→    let spec = parse_dot_rev(bare_rev);
251→    let (workspace, _) = load_repo(repo_path)?;
252→    let anchor_ids = resolve_revset(&workspace, repo, &spec.rev)?;
253→    if anchor_ids.is_empty() {
254→        return Err(format!("no commit found for revision '{}'", spec.rev).into());
255→    }
256→    let anchor_id = &anchor_ids[0];
257→    let root_commit_id = repo.store().root_commit_id().clone();
258→
259→    let ancestor_ids = resolve_revset(&workspace, repo, &format!("::{}", spec.rev))?;
260→    let descendant_ids = resolve_revset(&workspace, repo, &format!("{}::", spec.rev))?;
261→
262→    // Descendants (newest first from jj), excluding anchor
263→    let mut desc_lines: Vec<String> = Vec::new();
264→    for commit_id in &descendant_ids {
265→        if *commit_id == root_commit_id || *commit_id == *anchor_id {
266→            continue;
267→        }
268→        let commit = repo.store().get_commit(commit_id)?;
269→        desc_lines.push(formatter(&commit));
270→    }
271→    if both_count > 0 {
272→        let start = desc_lines.len().saturating_sub(both_count);
273→        desc_lines = desc_lines[start..].to_vec();
274→    } else {
275→        desc_lines.clear();
276→    }
277→
278→    // Anchor
279→    let anchor_commit = repo.store().get_commit(anchor_id)?;
280→
281→    // Ancestors (newest first from jj), excluding anchor
282→    let mut anc_lines: Vec<String> = Vec::new();
283→    if both_count > 0 {
284→        let mut count = 0;
285→        for commit_id in &ancestor_ids {
286→            if root_commit_id == *commit_id || *commit_id == *anchor_id {
287→                continue;
288→            }
289→            let commit = repo.store().get_commit(commit_id)?;
290→            anc_lines.push(formatter(&commit));
291→            count += 1;
292→            if count >= both_count {
293→                break;
294→            }
295→        }
296→    }
297→
298→    let mut result = desc_lines;
299→    result.push(formatter(&anchor_commit));
300→    result.extend(anc_lines);
301→    Ok(result)
302→}
