318→/// Parse and evaluate a revset string, returning commit IDs.
319→pub fn resolve_revset(
320→    workspace: &Workspace,
321→    repo: &Arc<ReadonlyRepo>,
322→    revset_str: &str,
323→) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
324→    let aliases_map = RevsetAliasesMap::new();
325→    let fileset_aliases_map = FilesetAliasesMap::new();
326→    let extensions = RevsetExtensions::default();
327→    let workspace_root = workspace.workspace_root().to_path_buf();
328→    let path_converter = RepoPathUiConverter::Fs {
329→        cwd: workspace_root.clone(),
330→        base: workspace_root,
331→    };
332→    let workspace_name = workspace.workspace_name();
333→    let workspace_ctx = RevsetWorkspaceContext {
334→        path_converter: &path_converter,
335→        workspace_name,
336→    };
337→    let context = RevsetParseContext {
338→        aliases_map: &aliases_map,
339→        local_variables: HashMap::new(),
340→        user_email: "",
341→        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
342→        default_ignored_remote: None,
343→        fileset_aliases_map: &fileset_aliases_map,
344→        use_glob_by_default: false,
345→        extensions: &extensions,
346→        workspace: Some(workspace_ctx),
347→    };
348→
349→    let mut diagnostics = RevsetDiagnostics::new();
350→    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
351→
352→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
353→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
354→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
355→    let revset = resolved.evaluate(repo.as_ref())?;
356→
357→    let mut commit_ids = Vec::new();
358→    for result in revset.iter() {
359→        commit_ids.push(result?);
360→    }
361→    Ok(commit_ids)
362→}
