 84→pub fn log_msg(log: &Path, msg: &str) {
 85→    let nanos = std::time::SystemTime::now()
 86→        .duration_since(std::time::UNIX_EPOCH)
 87→        .unwrap_or_default()
 88→        .as_nanos();
 89→    let pid = std::process::id();
 90→    let line = format!("[{nanos}] pid={pid} {msg}\n");
 91→    if let Ok(mut f) = std::fs::OpenOptions::new()
 92→        .create(true)
 93→        .append(true)
 94→        .open(log)
 95→    {
 96→        let _ = f.write_all(line.as_bytes());
 97→    }
 98→}
 99→
100→fn run_jj(args: &[&str], log: &Path) -> Result<(), Box<dyn std::error::Error>> {
101→    let args_str = args.join(" ");
102→    log_msg(log, &format!("run_jj: jj {args_str}"));
103→    let output = std::process::Command::new("jj")
104→        .args(args)
105→        .output()
106→        .map_err(|e| format!("failed to run jj: {e}"))?;
107→    let stdout = String::from_utf8_lossy(&output.stdout);
108→    let stderr = String::from_utf8_lossy(&output.stderr);
109→    if !stdout.is_empty() {
110→        log_msg(log, &format!("run_jj: stdout: {stdout}"));
111→    }
112→    if !stderr.is_empty() {
113→        log_msg(log, &format!("run_jj: stderr: {stderr}"));
114→    }
115→    if !output.status.success() {
116→        return Err(format!("jj {args_str} failed (exit {}): {stderr}", output.status).into());
117→    }
118→    Ok(())
119→}
120→
121→fn finalize_exec(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
122→    log_msg(&opts.log, &format!("finalize_exec: starting opts={opts:?}"));
123→
124→    // Sleep to let trailing writes settle
125→    let delay = std::time::Duration::from_secs_f64(opts.delay_secs);
126→    log_msg(&opts.log, &format!("finalize_exec: sleeping {delay:?}"));
127→    std::thread::sleep(delay);
128→
129→    // Squash source into target
130→    let repo_str = opts.repo.to_string_lossy();
131→    run_jj(
132→        &[
133→            "squash",
134→            "--ignore-immutable",
135→            "--use-destination-message",
136→            "--from",
137→            &opts.source,
138→            "--into",
139→            &opts.target,
140→            "-R",
141→            &repo_str,
142→        ],
143→        &opts.log,
144→    )?;
145→
146→    // Advance bookmark to target
147→    run_jj(
148→        &[
149→            "bookmark",
150→            "set",
151→            &opts.bookmark,
152→            "-r",
153→            &opts.target,
154→            "-R",
155→            &repo_str,
156→        ],
157→        &opts.log,
158→    )?;
159→
160→    if opts.push {
161→        run_jj(
162→            &["git", "push", "--bookmark", &opts.bookmark, "-R", &repo_str],
163→            &opts.log,
164→        )?;
165→    }
166→
167→    log_msg(&opts.log, "finalize_exec: done");
168→    Ok(())
169→}
