171→pub fn build_exec_args(opts: &FinalizeOpts) -> Vec<String> {
172→    let mut args = vec![
173→        "finalize".to_string(),
174→        "--exec".to_string(),
175→        "--repo".to_string(),
176→        opts.repo.to_string_lossy().to_string(),
177→        "--source".to_string(),
178→        opts.source.clone(),
179→        "--target".to_string(),
180→        opts.target.clone(),
181→        "--bookmark".to_string(),
182→        opts.bookmark.clone(),
183→        "--delay".to_string(),
184→        opts.delay_secs.to_string(),
185→        "--log".to_string(),
186→        opts.log.to_string_lossy().to_string(),
187→    ];
188→    if opts.push {
189→        args.push("--push".to_string());
190→    }
191→    args
192→}
