194→/// Spawn a detached child process with `--exec` and return immediately.
195→/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
196→/// it to `finalize_exec()` where the actual work happens.
197→fn daemonize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
198→    log_msg(
199→        &opts.log,
200→        &format!("daemonize: parent starting opts={opts:?}"),
201→    );
202→
203→    let exe = std::env::current_exe()?;
204→    let args = build_exec_args(opts);
205→    log_msg(&opts.log, &format!("daemonize: exe={exe:?} args={args:?}"));
206→
207→    let mut cmd = std::process::Command::new(exe);
208→    cmd.args(&args).stdin(Stdio::null());
209→
210→    #[cfg(unix)]
211→    {
212→        use std::os::unix::process::CommandExt;
213→        unsafe {
214→            cmd.pre_exec(|| {
215→                libc::setsid();
216→                Ok(())
217→            });
218→        }
219→    }
220→
221→    let child = cmd.spawn()?;
222→    log_msg(
223→        &opts.log,
224→        &format!("daemonize: spawned child pid={}", child.id()),
225→    );
226→    eprintln!(
227→        "finalize: daemonized (pid {}), log: {}",
228→        child.id(),
229→        opts.log.display()
230→    );
231→    Ok(())
232→}
233→
234→pub fn finalize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
235→    log_msg(&opts.log, &format!("finalize: entry opts={opts:?}"));
236→    let result = if opts.foreground || opts.exec {
237→        finalize_exec(opts)
238→    } else {
239→        daemonize(opts)
240→    };
241→    match &result {
242→        Ok(()) => log_msg(&opts.log, "finalize: exit ok"),
243→        Err(e) => log_msg(&opts.log, &format!("finalize: exit err={e}")),
244→    }
245→    result
246→}
